import type { CareerQuestion } from "./rrt-questions";

export const himQuestionsBatch2: CareerQuestion[] = [
  { id: "him-026", stem: "A patient with type 1 diabetes mellitus and diabetic retinopathy with macular edema is seen. What is the correct ICD-10-CM code?", options: ["E10.311","E10.319","E11.311","E10.36"], correctIndex: 0, rationale: "E10.311 captures type 1 diabetes with unspecified diabetic retinopathy with macular edema. Type 1 uses E10, not E11 (type 2). The 6th character specifies macular edema.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-027", stem: "A patient is admitted with diabetic ketoacidosis in type 1 diabetes without coma. The correct code is:", options: ["E10.10","E10.11","E13.10","E11.65"], correctIndex: 0, rationale: "E10.10 is the code for type 1 DM with ketoacidosis without coma. E10.11 would be with coma. E13 is other specified diabetes.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-028", stem: "Which category codes drug or chemical induced diabetes mellitus?", options: ["E09","E08","E10","E11"], correctIndex: 0, rationale: "E09 is for drug/chemical induced DM. E08 is DM due to underlying condition. E10 is type 1, E11 is type 2.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-029", stem: "A patient with type 2 DM and diabetic polyneuropathy should be coded as:", options: ["E11.42","E11.40","E11.621","E11.43"], correctIndex: 0, rationale: "E11.42 codes type 2 DM with diabetic polyneuropathy. E11.40 is unspecified neuropathy. E11.43 is autonomic neuropathy.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-030", stem: "Type 2 diabetes with diabetic chronic kidney disease stage 4. Correct codes?", options: ["E11.22 and N18.4","N18.4 only","E11.65 and N18.4","E11.9 and N18.9"], correctIndex: 0, rationale: "E11.22 codes type 2 DM with diabetic CKD. N18.4 identifies stage 4. The diabetes code is sequenced first per guidelines.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-031", stem: "Diabetes mellitus due to underlying condition with hyperglycemia is coded:", options: ["E08.65","E08.9","E11.65","E09.65"], correctIndex: 0, rationale: "E08.65 is DM due to underlying condition with hyperglycemia. The underlying condition is coded first, then E08.65.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-032", stem: "A patient with gestational DM controlled by insulin in the second trimester:", options: ["O24.414","O24.410","O24.419","E11.9"], correctIndex: 0, rationale: "O24.414 is gestational DM in pregnancy, insulin controlled. O24.410 is diet controlled. Z79.4 is also assigned for long-term insulin use.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-033", stem: "Type 2 DM with diabetic macular edema. What codes apply?", options: ["E11.311","E11.319","E11.36","E10.311"], correctIndex: 0, rationale: "E11.311 is type 2 DM with unspecified diabetic retinopathy with macular edema. The 6th character 1 indicates macular edema is present.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-034", stem: "A patient admitted for radiation therapy for metastatic lung cancer. Principal diagnosis?", options: ["Z51.0","C34.90","C79.31","C80.0"], correctIndex: 0, rationale: "When encounter is solely for radiation therapy, Z51.0 is sequenced first. The neoplasm codes follow as additional diagnoses.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-035", stem: "Primary ascending colon cancer with liver metastasis. Code sequence?", options: ["C18.2, C78.7","C78.7, C18.2","C18.2 only","C80.1, C78.7"], correctIndex: 0, rationale: "Primary neoplasm (C18.2) sequenced first, followed by secondary site (C78.7). Primary site directs treatment decisions.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-036", stem: "Patient with breast cancer history in remission for screening mammography:", options: ["Z85.3, Z12.31","C50.919, Z12.31","Z80.3, Z12.31","C50.911"], correctIndex: 0, rationale: "Z85.3 indicates personal history of breast malignancy (remission). Z12.31 for screening mammography. Active cancer codes not used when in remission.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-037", stem: "Carcinoma in situ of cervix uteri is coded to:", options: ["D06","C53","D39","N87"], correctIndex: 0, rationale: "D06 captures carcinoma in situ of cervix. C53 is invasive cervical malignancy. D39 is uncertain behavior. N87 is dysplasia.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-038", stem: "Benign lipoma of skin of trunk. Correct code?", options: ["D17.1","D17.0","C49.3","D21.3"], correctIndex: 0, rationale: "D17.1 codes benign lipomatous neoplasm of skin/subcutaneous tissue of trunk. D17.0 is head/face/neck.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-039", stem: "A patient with contiguous sites of malignancy involving the stomach and small intestine:", options: ["C26.8","C16.9, C17.9","C16.8","C80.0"], correctIndex: 0, rationale: "When a neoplasm overlaps contiguous sites and the point of origin cannot be determined, assign the code for overlapping sites (C26.8 for digestive organs).", difficulty: 4, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-040", stem: "Screening encounter for malignant neoplasm of colon in a 55-year-old. Code?", options: ["Z12.11","Z12.12","Z80.0","C18.9"], correctIndex: 0, rationale: "Z12.11 is the code for encounter for screening for malignant neoplasm of colon. Z12.12 is rectum. Z80.0 is family history.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-041", stem: "Secondary malignant neoplasm of the brain from primary breast cancer:", options: ["C79.31","C71.9","C50.919, C79.31","D49.6"], correctIndex: 0, rationale: "C79.31 is secondary malignant neoplasm of the brain. If the primary breast cancer is still active, C50.- is also coded.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-042", stem: "Open total right nephrectomy root operation?", options: ["Resection","Excision","Destruction","Extraction"], correctIndex: 0, rationale: "Resection (T) cuts out ALL of a body part. Total nephrectomy removes the entire kidney. Excision removes a portion.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-043", stem: "Arthroscopic partial medial meniscectomy of right knee:", options: ["Excision","Resection","Repair","Extraction"], correctIndex: 0, rationale: "Excision (B) cuts out a PORTION. Partial meniscectomy removes part of the meniscus, not all of it.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-044", stem: "Percutaneous drainage of liver abscess with catheter:", options: ["Drainage","Extraction","Excision","Release"], correctIndex: 0, rationale: "Drainage (9) takes/lets out fluids from a body part. The catheter is captured in the device value.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-045", stem: "Open reduction internal fixation of femoral shaft fracture:", options: ["Reposition","Repair","Replacement","Insertion"], correctIndex: 0, rationale: "Reposition (S) moves a body part to its normal location. ORIF repositions the fractured bone. Fixation device captured separately.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-046", stem: "Lysis of peritoneal adhesions via laparoscopy:", options: ["Release","Division","Excision","Destruction"], correctIndex: 0, rationale: "Release (N) frees a body part from abnormal physical constraint. Lysis of adhesions releases constrained tissue.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-047", stem: "Diagnostic bronchoscopy with biopsy of right upper lobe bronchus:", options: ["Excision","Inspection","Drainage","Extraction"], correctIndex: 0, rationale: "A biopsy removes a portion of tissue and is classified as Excision (B). Inspection alone would be diagnostic without biopsy.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-048", stem: "Removal of previously placed pacemaker generator:", options: ["Removal","Change","Revision","Extraction"], correctIndex: 0, rationale: "Removal (P) takes out a device from a body part. This applies to taking out devices that were previously put in.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-049", stem: "Percutaneous endoscopic appendectomy:", options: ["Resection","Excision","Destruction","Release"], correctIndex: 0, rationale: "The entire appendix is removed, making it Resection (T). Laparoscopic approach = percutaneous endoscopic (4).", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-050", stem: "Mechanical dilation of urethral stricture:", options: ["Dilation","Release","Excision","Destruction"], correctIndex: 0, rationale: "Dilation (7) expands an orifice or lumen. Urethral stricture dilation expands the narrowed urethra.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-051", stem: "Extracorporeal shock wave lithotripsy of kidney stone:", options: ["Fragmentation","Destruction","Extraction","Excision"], correctIndex: 0, rationale: "Fragmentation (F) breaks solid matter into pieces. ESWL breaks kidney stones using shock waves. Extracorporeal approach.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-052", stem: "The minimum necessary standard applies to which disclosure?", options: ["Payment purposes","Individual patient requests","Treatment between providers","Public health reporting required by law"], correctIndex: 0, rationale: "Minimum necessary applies to payment and operations. Does NOT apply to treatment, disclosures to individual, or those required by law.", difficulty: 3, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-053", stem: "Hospital receives valid subpoena without court order. What to do?", options: ["Verify reasonable efforts to notify patient or obtain qualified protective order","Release all records immediately","Refuse without court order","Release only face sheet"], correctIndex: 0, rationale: "HIPAA requires patient notification or qualified protective order before releasing PHI pursuant to subpoena without court order.", difficulty: 3, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-054", stem: "Which is NOT considered PHI under HIPAA?", options: ["De-identified data meeting safe harbor criteria","Patient diagnosis in chart","Electronic insurance claims","Lab results in EHR"], correctIndex: 0, rationale: "De-identified data meeting safe harbor method (removal of 18 identifiers) is not PHI. All others contain individually identifiable health info.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-055", stem: "How long must HIPAA policies be retained?", options: ["6 years from creation or last effective date","5 years","7 years","10 years"], correctIndex: 0, rationale: "HIPAA requires retaining policies for 6 years from creation or date last in effect, whichever is later.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-056", stem: "Patient amendment request response timeline:", options: ["60 days with one 30-day extension","30 days, no extension","90 days, no extension","45 days with 30-day extension"], correctIndex: 0, rationale: "HIPAA gives 60 days to act on amendment requests, with one 30-day extension if written explanation is provided.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-057", stem: "A business associate agreement must include:", options: ["Requirements for safeguarding PHI and breach notification procedures","Only the payment terms for services","Permission to sell PHI to third parties","Waiver of all HIPAA requirements"], correctIndex: 0, rationale: "BAAs must specify how the BA will safeguard PHI, limit its use, and report breaches. They extend HIPAA requirements to the BA.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-058", stem: "Patients have the right to request restriction on disclosures of PHI to health plans for services:", options: ["Paid for entirely out of pocket by the patient","Covered by Medicare","Related to emergency services","Involving psychiatric treatment only"], correctIndex: 0, rationale: "Under HITECH, patients can restrict disclosure to health plans for services they pay for entirely out of pocket, and providers must comply.", difficulty: 3, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-059", stem: "The designated record set includes:", options: ["Medical records, billing records, and enrollment/payment records used to make decisions about individuals","All data in every IT system","Only paper medical charts","Research data exclusively"], correctIndex: 0, rationale: "The designated record set encompasses records used to make decisions about individuals including medical, billing, and enrollment records.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-060", stem: "HIPAA Security Rule requires which safeguards?", options: ["Administrative, physical, and technical","Technical only","Administrative only","Physical and encryption only"], correctIndex: 0, rationale: "Three categories: administrative (policies, training), physical (facility access, workstation), technical (access controls, encryption, audit).", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-061", stem: "Risk analysis under Security Rule must:", options: ["Identify and assess potential risks to confidentiality, integrity, availability of ePHI","Only assess external threats","Be done once, never updated","Focus on network security only"], correctIndex: 0, rationale: "Thorough risk analysis identifies all threats/vulnerabilities to ePHI, assesses likelihood and impact, must be regularly updated.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-062", stem: "Example of technical safeguard:", options: ["Access controls like unique user ID and automatic logoff","Security awareness training","Locked server rooms","Contingency planning for backup"], correctIndex: 0, rationale: "Technical safeguards: access controls, audit controls, integrity controls, transmission security. Training is administrative; locks are physical.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-063", stem: "Breach notification timeline to individuals:", options: ["60 days from discovery","30 days","90 days","24 hours"], correctIndex: 0, rationale: "HIPAA Breach Notification requires notification within 60 days of discovery. Breaches affecting 500+ require media/HHS notification.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-064", stem: "Encryption of ePHI in transit is classified as which type of safeguard?", options: ["Technical","Administrative","Physical","Organizational"], correctIndex: 0, rationale: "Encryption is a technical safeguard under the Security Rule. It protects ePHI during electronic transmission.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-065", stem: "Administrative safeguards include all EXCEPT:", options: ["Biometric access locks on server rooms","Security awareness training","Risk management programs","Workforce clearance procedures"], correctIndex: 0, rationale: "Biometric locks are physical safeguards. Administrative safeguards include training, risk management, workforce clearance, and security management process.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-066", stem: "Which form submits institutional claims?", options: ["UB-04 (CMS-1450)","CMS-1500","ADA Dental Form","CMS-855"], correctIndex: 0, rationale: "UB-04 for institutional providers (hospitals). CMS-1500 for professional/physician claims. CMS-855 is enrollment.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-067", stem: "Denial for lack of medical necessity classification:", options: ["Clinical denial","Technical denial","Administrative denial","Authorization denial"], correctIndex: 0, rationale: "Medical necessity denials are clinical denials. Technical denials relate to billing errors.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-068", stem: "MS-DRGs used under which payment system?", options: ["Medicare IPPS","Medicare OPPS","RBRVS","APCs"], correctIndex: 0, rationale: "MS-DRGs determine payment under IPPS for inpatient stays. OPPS uses APCs. RBRVS for physician services.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-069", stem: "Purpose of chargemaster in revenue cycle?", options: ["Comprehensive list of billable items and charges for claims","Tool for coding diagnoses","Track insurance eligibility","Process claim denials"], correctIndex: 0, rationale: "Chargemaster contains all billable items, services, procedures with charges, revenue codes, and CPT/HCPCS codes.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-070", stem: "APCs used under which Medicare payment model?", options: ["OPPS","IPPS","Home Health PPS","SNF PPS"], correctIndex: 0, rationale: "APCs classify outpatient services for OPPS payment. IPPS uses DRGs.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-071", stem: "What does 'DRG creep' refer to?", options: ["Systematic practice of assigning higher-weighted DRGs to increase reimbursement beyond what is supported by documentation","Natural increase in case severity over time","Software errors in DRG assignment","Physician documentation improvement"], correctIndex: 0, rationale: "DRG creep is the inappropriate assignment of higher-paying DRGs not supported by clinical documentation, constituting potential fraud.", difficulty: 3, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-072", stem: "A remittance advice (RA/ERA) provides:", options: ["Payment information, adjustments, and reasons for claim denial or reduction","Patient demographic information only","Physician credentialing status","Drug formulary listings"], correctIndex: 0, rationale: "The RA/ERA provides detailed payment information including amounts paid, adjustments, claim status, and reason codes for denials.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-073", stem: "Chart shows 'pneumonia.' What CDI query?", options: ["Request specification of type, organism, community vs hospital-acquired","No query; code J18.9","Code as bacterial since on antibiotics","Wait until discharge"], correctIndex: 0, rationale: "Unspecified pneumonia (J18.9) has lower DRG weight. CDI queries should request specificity for accurate DRG assignment.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "CDI Programs" },
  { id: "him-074", stem: "Clinical indicator supporting sepsis query?", options: ["Two+ SIRS criteria plus documented/suspected infection","Elevated WBC alone","Single tachycardia episode","Mild temp elevation alone"], correctIndex: 0, rationale: "Sepsis requires infection plus systemic response. Two+ SIRS criteria with infection supports a sepsis query.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "CDI Programs" },
  { id: "him-075", stem: "Primary purpose of CDI program?", options: ["Ensure accurate documentation reflecting severity and resource use","Increase revenue through upcoding","Replace physician documentation","Reduce codes per encounter"], correctIndex: 0, rationale: "CDI ensures documentation accurately reflects condition, severity, and resources used for accurate coding and quality reporting.", difficulty: 1, category: "Clinical Documentation Improvement", topic: "CDI Programs" },
  { id: "him-076", stem: "A compliant physician query must NOT include:", options: ["A suggested specific diagnosis","Clinical indicators from the record","Open-ended format","Health record number"], correctIndex: 0, rationale: "Queries should NOT lead to specific diagnosis. They present indicators and use open-ended/multiple-choice for physician judgment.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "CDI Programs" },
  { id: "him-077", stem: "Which clinical scenario would trigger a CDI review for possible acute kidney injury?", options: ["Creatinine increase of 0.3 mg/dL or more within 48 hours with IV fluid administration","Stable creatinine over several days","Normal urinary output without medication changes","Documented chronic kidney disease without change"], correctIndex: 0, rationale: "An acute creatinine rise of ≥0.3 mg/dL within 48 hours meets KDIGO criteria for AKI. CDI review ensures proper documentation and coding.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "CDI Programs" },
  { id: "him-078", stem: "What is the impact of CDI on quality reporting measures?", options: ["Accurate severity adjustment reflects true patient acuity for risk-adjusted outcomes","CDI has no impact on quality measures","CDI only affects financial reimbursement","CDI reduces the number of reportable conditions"], correctIndex: 0, rationale: "CDI improves documentation accuracy which directly impacts risk adjustment, severity of illness, and mortality indices used in quality reporting.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Programs" },
  { id: "him-079", stem: "Hospital gross death rate formula:", options: ["Total inpatient deaths / total discharges × 100","Total deaths / total admissions × 100","Deaths / average daily census × 100","All deaths / total encounters × 100"], correctIndex: 0, rationale: "Gross death rate = inpatient deaths ÷ total discharges (including deaths) × 100. Standard hospital vital statistic.", difficulty: 2, category: "Health Data Analytics", topic: "Statistical Methods" },
  { id: "him-080", stem: "Hospital infection rate formula:", options: ["Hospital-acquired infections / total discharges × 100","All infections / total admissions × 100","Community infections / total discharges × 100","HAIs / infected patients × 100"], correctIndex: 0, rationale: "Hospital infection rate uses nosocomial infections divided by total discharges times 100. Community-acquired excluded.", difficulty: 2, category: "Health Data Analytics", topic: "Statistical Methods" },
  { id: "him-081", stem: "Case mix index (CMI) measures:", options: ["Average DRG relative weight reflecting severity and resource intensity","Total cases seen","Bed occupancy percentage","Surgical to medical ratio"], correctIndex: 0, rationale: "CMI is average of all DRG relative weights. Higher CMI = greater severity/complexity, higher resource utilization.", difficulty: 2, category: "Health Data Analytics", topic: "Statistical Methods" },
  { id: "him-082", stem: "ALOS calculation:", options: ["Total discharge days / total discharges","Total admissions / bed days","Total bed days / admissions","Discharges / total LOS"], correctIndex: 0, rationale: "ALOS = total discharge days (sum of individual LOS) divided by total discharges.", difficulty: 1, category: "Health Data Analytics", topic: "Statistical Methods" },
  { id: "him-083", stem: "Bed occupancy rate is calculated as:", options: ["Inpatient service days / (bed count × days in period) × 100","Total admissions / bed count","Total discharges / bed count × 100","Average daily census / total admissions"], correctIndex: 0, rationale: "Bed occupancy rate = inpatient service days ÷ (number of beds × number of days in period) × 100.", difficulty: 2, category: "Health Data Analytics", topic: "Statistical Methods" },
  { id: "him-084", stem: "The C-section rate is an example of:", options: ["A procedure-specific rate","A gross mortality rate","An autopsy rate","An infection rate"], correctIndex: 0, rationale: "C-section rate (C-sections / total deliveries × 100) is a procedure-specific rate used for quality monitoring.", difficulty: 1, category: "Health Data Analytics", topic: "Statistical Methods" },
  { id: "him-085", stem: "HL7 FHIR uses which technology?", options: ["RESTful APIs with JSON/XML","SOAP web services only","Direct file transfer","Proprietary DB connections"], correctIndex: 0, rationale: "FHIR uses modern web standards: RESTful APIs with JSON/XML. Easier implementation than HL7 v2 and CDA.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Interoperability" },
  { id: "him-086", stem: "Standard for clinical document architecture:", options: ["HL7 CDA R2","DICOM","X12 5010","NCPDP"], correctIndex: 0, rationale: "HL7 CDA R2 for clinical documents. DICOM for imaging. X12 for admin transactions. NCPDP for pharmacy.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Interoperability" },
  { id: "him-087", stem: "21st Century Cures Act requires:", options: ["Information blocking prevention and patient API access","Mandatory cloud storage","Complete paper record replacement in 1 year","Auto-sharing without consent"], correctIndex: 0, rationale: "The Act prohibits information blocking and requires certified EHR technology to support patient access through standardized APIs.", difficulty: 3, category: "EHR Systems & Health IT", topic: "Interoperability" },
  { id: "him-088", stem: "DICOM standard is used for:", options: ["Medical imaging data exchange and storage","Laboratory results reporting","Pharmacy prescription transmission","Administrative claims processing"], correctIndex: 0, rationale: "DICOM (Digital Imaging and Communications in Medicine) is the standard for medical imaging data exchange, storage, and viewing.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Interoperability" },
  { id: "him-089", stem: "Meaningful Use (now Promoting Interoperability) requires:", options: ["Use of certified EHR technology to improve quality, safety, and efficiency","Paper-based documentation only","Manual data entry without electronic verification","Faxing of all medical records"], correctIndex: 0, rationale: "Meaningful Use/Promoting Interoperability requires certified EHR technology use with specific objectives for quality improvement and data exchange.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Interoperability" },
  { id: "him-090", stem: "2021 E/M office visit level determined by:", options: ["Medical decision making or total time","Body systems examined","HPI complexity","Number of diagnoses in history"], correctIndex: 0, rationale: "Revised 2021 guidelines base level on MDM complexity or total time, eliminating previous history and exam requirements.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-091", stem: "Modifier -25 indicates:", options: ["Significant, separately identifiable E/M on same day as procedure","Reduced service","Discontinued procedure","Unrelated E/M in post-op period"], correctIndex: 0, rationale: "Modifier -25 indicates significant, separately identifiable E/M by same physician on same day as another procedure.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-092", stem: "Modifier -59 indicates:", options: ["Distinct procedural service separate from other same-day services","Bilateral procedure","Assistant surgeon","Repeat procedure by same physician"], correctIndex: 0, rationale: "Modifier -59 identifies distinct/independent procedures from other same-day services. Overrides NCCI edits when truly separate.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-093", stem: "CPT surgical code range:", options: ["10004-69990","99201-99499","70010-79999","80047-89398"], correctIndex: 0, rationale: "Surgery codes: 10004-69990. E/M: 99201-99499. Radiology: 70010-79999. Path/Lab: 80047-89398.", difficulty: 1, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-094", stem: "Screening colonoscopy with polyp removal. How coded?", options: ["Polypectomy as primary; diagnostic colonoscopy included","Both separately with -59","Screening colonoscopy only","Unlisted procedure"], correctIndex: 0, rationale: "When screening converts to therapeutic (polypectomy), therapeutic code takes precedence. Diagnostic component is bundled.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-095", stem: "For a new patient office visit, the lowest level E/M code is:", options: ["99202","99201","99211","99203"], correctIndex: 0, rationale: "Under current guidelines, 99202 is the lowest new patient office visit code (99201 was deleted in 2021). 99211 is for established patients.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-096", stem: "MDM of moderate complexity requires:", options: ["Multiple diagnoses/management options with moderate data review and moderate risk","Single self-limited problem","Extensive data review with minimal risk","No data to review"], correctIndex: 0, rationale: "Moderate MDM requires moderate number/complexity of problems, moderate data to review, and moderate risk of complications/morbidity/mortality.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-097", stem: "False Claims Act imposes liability on those who:", options: ["Knowingly submit false claims to federal programs","Accidentally submit incorrect claim","Submit without verifying eligibility","Bill below market rates"], correctIndex: 0, rationale: "FCA imposes civil penalties for knowingly submitting false/fraudulent claims. 'Knowingly' includes deliberate ignorance or reckless disregard.", difficulty: 2, category: "Compliance & Legal", topic: "Fraud and Abuse" },
  { id: "him-098", stem: "OIG Work Plan used by organizations to:", options: ["Identify audit focus areas and proactively monitor compliance","Develop vacation schedules","Track physician productivity","Manage supply chain"], correctIndex: 0, rationale: "OIG Work Plan outlines areas targeted for audit. Organizations review annually to strengthen compliance.", difficulty: 2, category: "Compliance & Legal", topic: "Fraud and Abuse" },
  { id: "him-099", stem: "Unbundling in coding refers to:", options: ["Billing separately for services that should be a single code","Combining procedures into one code","Using modifiers appropriately","Failing to code all diagnoses"], correctIndex: 0, rationale: "Unbundling is billing individual components separately when a comprehensive code exists. Considered fraud if intentional.", difficulty: 2, category: "Compliance & Legal", topic: "Fraud and Abuse" },
  { id: "him-100", stem: "Anti-Kickback Statute prohibits:", options: ["Offering/receiving value to induce referrals for federal program services","All physician referrals","Accepting insurance payments","Marketing hospital services"], correctIndex: 0, rationale: "AKS prohibits knowingly offering, paying, soliciting, or receiving remuneration to induce referrals for federal healthcare program services.", difficulty: 2, category: "Compliance & Legal", topic: "Fraud and Abuse" },
  { id: "him-101", stem: "Stark Law specifically regulates:", options: ["Physician self-referral for designated health services to entities with financial relationships","All healthcare billing practices","Hospital staffing ratios","Drug prescribing patterns"], correctIndex: 0, rationale: "Stark Law (Physician Self-Referral Law) prohibits physicians from referring patients for designated health services to entities with which they have financial relationships, unless an exception applies.", difficulty: 3, category: "Compliance & Legal", topic: "Fraud and Abuse" },
  { id: "him-102", stem: "Qui tam provisions under the False Claims Act allow:", options: ["Private citizens to file lawsuits on behalf of the government against entities submitting false claims","Government agencies to audit hospitals without notice","Physicians to self-report coding errors without penalty","Insurance companies to deny all claims under investigation"], correctIndex: 0, rationale: "Qui tam (whistleblower) provisions allow private individuals to file suit on behalf of the government and potentially receive a percentage of the recovered funds.", difficulty: 3, category: "Compliance & Legal", topic: "Fraud and Abuse" },
  { id: "him-103", stem: "STEMI of anterior wall, initial episode:", options: ["I21.09","I21.19","I21.3","I25.2"], correctIndex: 0, rationale: "I21.09 codes STEMI of anterior wall. I21.19 is inferior. I21.3 is unspecified site. I25.2 is old MI.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Cardiovascular Coding" },
  { id: "him-104", stem: "Chronic atrial fibrillation code:", options: ["I48.20","I48.0","I48.1","I48.91"], correctIndex: 0, rationale: "I48.20 is chronic AF. I48.0 is paroxysmal. I48.1 is persistent. I48.91 is unspecified.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Cardiovascular Coding" },
  { id: "him-105", stem: "PCI with stent in LAD, approach value:", options: ["3 (Percutaneous)","4 (Percutaneous endoscopic)","0 (Open)","7 (Via natural opening)"], correctIndex: 0, rationale: "PCI via catheterization uses percutaneous approach (3). Catheter enters through skin puncture to reach coronaries.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Cardiovascular Coding" },
  { id: "him-106", stem: "Chronic diastolic heart failure code:", options: ["I50.32","I50.30","I50.22","I50.9"], correctIndex: 0, rationale: "I50.32 is chronic diastolic HF. I50.30 is unspecified diastolic. I50.22 is chronic systolic. I50.9 is unspecified HF.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Cardiovascular Coding" },
  { id: "him-107", stem: "Acute on chronic combined systolic and diastolic heart failure:", options: ["I50.43","I50.41","I50.33","I50.23"], correctIndex: 0, rationale: "I50.43 is acute on chronic combined systolic and diastolic heart failure. This captures both the acute and chronic components.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Cardiovascular Coding" },
  { id: "him-108", stem: "Hypertensive heart disease with heart failure is coded:", options: ["I11.0 with heart failure code","I10, I50.9","I11.9 only","I13.0 only"], correctIndex: 0, rationale: "ICD-10-CM assumes a causal relationship between hypertension and heart disease. I11.0 is used with an additional code for the type of heart failure.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Cardiovascular Coding" },
  { id: "him-109", stem: "C-section for CPD at 38 weeks, single liveborn. Principal dx?", options: ["O33.9 with Z37.0","Z37.0 only","O82","O80"], correctIndex: 0, rationale: "Condition necessitating C-section (O33.9) is principal. Z37.0 (single live birth) is always additional on maternal record.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Obstetric Coding" },
  { id: "him-110", stem: "Chapter 15 covers:", options: ["Pregnancy, childbirth, puerperium (O00-O9A)","Perinatal conditions (P00-P96)","Genitourinary (N00-N99)","Z codes (Z00-Z99)"], correctIndex: 0, rationale: "Chapter 15 covers pregnancy/childbirth. Chapter 16 is perinatal. Chapter 14 is GU.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Obstetric Coding" },
  { id: "him-111", stem: "Gestational DM, diet controlled:", options: ["O24.410","O24.414","E11.9","O24.019"], correctIndex: 0, rationale: "O24.410 is gestational DM diet controlled. O24.414 is insulin controlled. E11.9 is type 2 (not gestational).", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Obstetric Coding" },
  { id: "him-112", stem: "Pre-eclampsia in third trimester, mild:", options: ["O14.03","O14.13","O14.93","O11.3"], correctIndex: 0, rationale: "O14.03 is mild pre-eclampsia, third trimester. O14.13 is severe. O11.3 is pre-existing hypertension with pre-eclampsia.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Obstetric Coding" },
  { id: "him-113", stem: "Outcome of delivery code Z37 is used on which record?", options: ["Mother's record only","Newborn record only","Both mother and newborn","Neither record"], correctIndex: 0, rationale: "Z37 outcome of delivery codes are used ONLY on the maternal record, never on the newborn record.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Obstetric Coding" },
  { id: "him-114", stem: "Traumatic subdural hemorrhage with LOC 45 min, initial:", options: ["S06.5X3A","S06.5X1A","S06.5X9A","S06.6X3A"], correctIndex: 0, rationale: "S06.5X3A = subdural hemorrhage with LOC 31-59 min, initial encounter. 6th char = LOC duration. A = initial.", difficulty: 4, category: "ICD-10-CM/PCS Coding", topic: "Injury Coding" },
  { id: "him-115", stem: "7th character 'D' indicates:", options: ["Subsequent encounter for routine healing","Initial encounter","Sequela","Active treatment phase"], correctIndex: 0, rationale: "D = subsequent encounter during healing. A = initial (active treatment). S = sequela (late effect).", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Injury Coding" },
  { id: "him-116", stem: "Laterality in injury codes captured in which position?", options: ["5th or 6th character","1st character","3rd character","7th character only"], correctIndex: 0, rationale: "Laterality typically in 5th/6th character position depending on code structure. 7th character = encounter type.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Injury Coding" },
  { id: "him-117", stem: "A patient has a nondisplaced fracture of the distal radius. How does ICD-10-CM differentiate displaced vs nondisplaced?", options: ["Through the 6th character of the code","Through the 4th character","Through the 7th character","Through a separate modifier code"], correctIndex: 0, rationale: "ICD-10-CM uses the 6th character to differentiate displaced from nondisplaced fractures. Even-numbered values typically indicate nondisplaced.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Injury Coding" },
  { id: "him-118", stem: "External cause codes (V00-Y99) are used to:", options: ["Identify the cause, intent, and place of injury events","Replace the injury diagnosis code","Code only motor vehicle accidents","Identify the treating physician"], correctIndex: 0, rationale: "External cause codes capture how the injury occurred, the intent (accident, assault, self-harm), and the place of occurrence. They are additional codes, never principal.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Injury Coding" },
  { id: "him-119", stem: "Modifier for multiple procedures through same incision:", options: ["-51 (Multiple Procedures)","-59 (Distinct Service)","-50 (Bilateral)","-62 (Two Surgeons)"], correctIndex: 0, rationale: "Modifier -51 for multiple procedures in same session. Applied to secondary/lesser procedures. Payment reduced for subsequent.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Surgical Coding" },
  { id: "him-120", stem: "Global surgical package excludes:", options: ["Unrelated E/M during post-op period","Pre-op eval on day of surgery","Intraoperative services","Routine follow-up care"], correctIndex: 0, rationale: "Global package includes pre-op on surgery day, procedure, and routine post-op. Unrelated E/M separately reportable with -24.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "Surgical Coding" },
  { id: "him-121", stem: "NCCI edits designed to:", options: ["Prevent improper payment for services not billed together","Determine eligibility","Calculate reimbursement","Track quality metrics"], correctIndex: 0, rationale: "NCCI edits identify code pairs that shouldn't be billed together, preventing unbundling and duplicate billing.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Surgical Coding" },
  { id: "him-122", stem: "Modifier -26 indicates:", options: ["Professional component of a diagnostic test","Technical component","Bilateral procedure","Reduced service"], correctIndex: 0, rationale: "Modifier -26 identifies the professional component (physician interpretation) of a diagnostic test. -TC is the technical component.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Surgical Coding" },
  { id: "him-123", stem: "An add-on code in CPT:", options: ["Cannot be reported alone and must be used with a primary procedure code","Can be reported as a standalone procedure","Requires modifier -51","Replaces the primary procedure code"], correctIndex: 0, rationale: "Add-on codes (designated with +) are performed in addition to a primary procedure and cannot be reported alone. Modifier -51 is not applied to add-on codes.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Surgical Coding" },
  { id: "him-124", stem: "Acute respiratory failure with hypoxia:", options: ["J96.01","J96.00","J96.11","J96.91"], correctIndex: 0, rationale: "J96.01 is acute respiratory failure with hypoxia. J96.00 is unspecified. J96.11 is chronic with hypoxia.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Respiratory Coding" },
  { id: "him-125", stem: "COPD with acute exacerbation and acute bronchitis:", options: ["J44.0 and J20.9","J44.1 and J20.9","J44.9 only","J20.9 only"], correctIndex: 0, rationale: "COPD with acute infection: J44.0 plus additional code for bronchitis (J20.x). J44.1 is exacerbation without infection.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Respiratory Coding" },
  { id: "him-126", stem: "Ventilator-associated pneumonia code:", options: ["J95.851","J18.9","J95.89","T81.44XA"], correctIndex: 0, rationale: "J95.851 specifically codes VAP. Additional code identifies organism. J18.9 is unspecified pneumonia.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Respiratory Coding" },
  { id: "him-127", stem: "Acute asthma exacerbation with status asthmaticus:", options: ["J45.901","J45.20","J45.40","J45.998"], correctIndex: 0, rationale: "J45.901 is unspecified asthma with status asthmaticus. Status asthmaticus represents a life-threatening exacerbation not responsive to standard therapy.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Respiratory Coding" },
  { id: "him-128", stem: "Bilateral pneumonia due to Streptococcus pneumoniae:", options: ["J13","J18.1","J15.9","J18.9"], correctIndex: 0, rationale: "J13 codes pneumonia due to Streptococcus pneumoniae. Bilateral does not affect the code assignment in ICD-10-CM for organism-specific pneumonia.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Respiratory Coding" },
  { id: "him-129", stem: "Most effective strategy for reducing denials?", options: ["Front-end eligibility verification and clean claims","Wait until denial to check eligibility","Submit without documentation review","Appeal all denials regardless"], correctIndex: 0, rationale: "Proactive denial prevention through front-end processes is more effective than reactive denial management.", difficulty: 2, category: "Revenue Cycle Management", topic: "Denial Management" },
  { id: "him-130", stem: "Clean claim definition:", options: ["Contains all required data, processable without additional info","No diagnosis codes","Paper claim","Single procedure code only"], correctIndex: 0, rationale: "Clean claim has all required elements, is deficiency-free, passes editing criteria for adjudication without additional info.", difficulty: 1, category: "Revenue Cycle Management", topic: "Denial Management" },
  { id: "him-131", stem: "The most common reason for claim denials is:", options: ["Incomplete or inaccurate patient registration and eligibility information","Incorrect CPT codes","Missing physician signatures","Use of wrong claim form"], correctIndex: 0, rationale: "Registration and eligibility issues (incorrect demographics, expired coverage) are the leading cause of claim denials, making front-end verification critical.", difficulty: 2, category: "Revenue Cycle Management", topic: "Denial Management" },
  { id: "him-132", stem: "A clinical appeal for a denied claim should include:", options: ["Medical records, physician attestation, and clinical evidence supporting medical necessity","Only the original claim form","A letter from the patient","Financial hardship documentation"], correctIndex: 0, rationale: "Clinical appeals require supporting medical documentation, physician statements, and clinical evidence demonstrating the service was medically necessary.", difficulty: 2, category: "Revenue Cycle Management", topic: "Denial Management" },
  { id: "him-133", stem: "Adult health records retained minimum:", options: ["10 years from last encounter","5 years","Age of majority + statute of limitations","1 year"], correctIndex: 0, rationale: "AHIMA recommends 10 years for adult records. State laws may require longer. Minor records: age of majority + statute of limitations.", difficulty: 2, category: "Health Data Management", topic: "Record Retention" },
  { id: "him-134", stem: "Legal health record (LHR) defined as:", options: ["Documentation constituting the business record, disclosed upon request","All data in EHR including metadata","Only paper records","Documents for litigation"], correctIndex: 0, rationale: "LHR is the subset used for business records and legal/regulatory disclosure purposes.", difficulty: 2, category: "Health Data Management", topic: "Record Retention" },
  { id: "him-135", stem: "Which organization accredits healthcare facilities?", options: ["The Joint Commission (TJC)","AMA","CDC","AHIMA"], correctIndex: 0, rationale: "TJC accredits healthcare organizations and sets documentation standards for authentication, completeness, timeliness.", difficulty: 1, category: "Health Data Management", topic: "Record Retention" },
  { id: "him-136", stem: "The master patient index (MPI) contains:", options: ["Unique patient identification data linking all records across the organization","Only financial information","Clinical diagnosis data only","Physician credentialing information"], correctIndex: 0, rationale: "The MPI is a database of unique patient identifiers that links patients to their health records across the organization. It is critical for record integrity.", difficulty: 1, category: "Health Data Management", topic: "Record Retention" },
  { id: "him-137", stem: "Record destruction should be documented by:", options: ["A certificate of destruction that includes method, date, and witness attestation","Verbal confirmation only","No documentation required","A note in the patient's active chart"], correctIndex: 0, rationale: "Record destruction requires formal documentation (certificate) specifying the method of destruction, date, and witness to ensure compliance and accountability.", difficulty: 2, category: "Health Data Management", topic: "Record Retention" },
  { id: "him-138", stem: "Sepsis due to MRSA coding:", options: ["A41.02 with B95.62","A41.9","A49.02","R65.20"], correctIndex: 0, rationale: "A41.02 specifically codes sepsis due to MRSA. B95.62 identifies MRSA organism as additional code.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Infectious Disease Coding" },
  { id: "him-139", stem: "Severe sepsis with septic shock:", options: ["R65.21 with underlying infection code and organ dysfunction codes","A41.9 only","R65.20 only","T81.12XA"], correctIndex: 0, rationale: "Severe sepsis with shock requires: underlying infection code first, R65.21 (severe sepsis with shock), plus organ dysfunction codes.", difficulty: 4, category: "ICD-10-CM/PCS Coding", topic: "Infectious Disease Coding" },
  { id: "him-140", stem: "COVID-19 confirmed case code:", options: ["U07.1","U07.2","J12.89","Z20.822"], correctIndex: 0, rationale: "U07.1 codes confirmed COVID-19. U07.2 was used for clinically diagnosed (no longer valid). J12.89 is other viral pneumonia. Z20.822 is exposure contact.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Infectious Disease Coding" },
  { id: "him-141", stem: "Clostridioides difficile (C. diff) enterocolitis:", options: ["A04.72","A04.71","A09","K52.89"], correctIndex: 0, rationale: "A04.72 codes C. diff enterocolitis (with megacolon). A04.71 is C. diff without megacolon. A09 is infectious GI disease unspecified.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Infectious Disease Coding" },
  { id: "him-142", stem: "UTI due to E. coli:", options: ["N39.0 with B96.20","N39.0 only","B96.20 only","N30.00"], correctIndex: 0, rationale: "N39.0 codes the UTI. B96.20 identifies E. coli as the causative organism. Both codes are needed per coding guidelines.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Infectious Disease Coding" },
  { id: "him-143", stem: "Major depressive disorder, single episode, moderate:", options: ["F32.1","F32.0","F33.1","F32.9"], correctIndex: 0, rationale: "F32.1 is major depressive disorder, single episode, moderate. F32.0 is mild. F33 is recurrent. F32.9 is unspecified.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Mental Health Coding" },
  { id: "him-144", stem: "Alcohol dependence with withdrawal delirium:", options: ["F10.231","F10.230","F10.239","F10.129"], correctIndex: 0, rationale: "F10.231 codes alcohol dependence with withdrawal delirium (delirium tremens). The 5th and 6th characters specify the type of withdrawal complication.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Mental Health Coding" },
  { id: "him-145", stem: "Opioid dependence with opioid-induced mood disorder:", options: ["F11.24","F11.20","F11.23","F11.29"], correctIndex: 0, rationale: "F11.24 codes opioid dependence with opioid-induced depressive disorder. Combination codes capture both the dependence and the mental health manifestation.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Mental Health Coding" },
  { id: "him-146", stem: "Adjustment disorder with mixed anxiety and depressed mood:", options: ["F43.23","F43.20","F43.21","F43.22"], correctIndex: 0, rationale: "F43.23 is adjustment disorder with mixed anxiety and depressed mood. F43.21 is with depressed mood only. F43.22 is with anxiety only.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Mental Health Coding" },
  { id: "him-147", stem: "Primary hyperparathyroidism:", options: ["E21.0","E21.1","E21.3","E20.0"], correctIndex: 0, rationale: "E21.0 codes primary hyperparathyroidism. E21.1 is secondary. E21.3 is hyperparathyroidism unspecified. E20.0 is hypoparathyroidism.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Endocrine Coding" },
  { id: "him-148", stem: "Hypothyroidism due to medications:", options: ["E03.2","E03.9","E01.8","E06.3"], correctIndex: 0, rationale: "E03.2 codes hypothyroidism due to medicaments and other exogenous substances. An additional external cause code identifies the medication.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Endocrine Coding" },
  { id: "him-149", stem: "Cushing syndrome due to pituitary adenoma:", options: ["E24.0","E24.2","E24.9","D35.2"], correctIndex: 0, rationale: "E24.0 is pituitary-dependent Cushing disease. E24.2 is drug-induced. D35.2 codes the pituitary adenoma separately.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Endocrine Coding" },
  { id: "him-150", stem: "Rheumatoid arthritis of multiple sites with rheumatoid factor:", options: ["M05.79","M05.70","M06.09","M06.89"], correctIndex: 0, rationale: "M05.79 codes RA with rheumatoid factor of multiple sites. M05 category requires positive rheumatoid factor.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Musculoskeletal Coding" },
  { id: "him-151", stem: "Pathological fracture of vertebra due to osteoporosis:", options: ["M80.08XA","M84.48XA","S32.009A","M80.00XA"], correctIndex: 0, rationale: "M80.08XA codes age-related osteoporosis with current pathological fracture of vertebra(e), initial encounter.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Musculoskeletal Coding" },
  { id: "him-152", stem: "Lumbar disc herniation with radiculopathy:", options: ["M51.16","M51.06","M54.5","M47.816"], correctIndex: 0, rationale: "M51.16 codes intervertebral disc disorders with radiculopathy at lumbar region. M51.06 is lumbar without radiculopathy.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Musculoskeletal Coding" },
];
